questionvariables.text:
/* Q3: Hertzian Dipole — Validity Check and Design Correction */
/* ALL variants have l/lambda > 0.1 (invalid Hertzian dipole) */
idx: 1 + rand(5);

l_cm_list: [5, 10, 8, 4, 15];
I_0_list: [1, 2, 0.5, 5, 1];
f_GHz_list: [1, 2, 5, 2, 0.5];

l_cm: l_cm_list[idx];
I_0: I_0_list[idx];
f_GHz: f_GHz_list[idx];

c0: 3*10^8;
l_m: l_cm / 100;
f_Hz: f_GHz * 10^9;

/* (a) Wavelength */
lambda_val: float(c0 / f_Hz);
tans1: lambda_val;

/* (b) l/lambda ratio — always > 0.1 */
ratio_val: float(l_m / lambda_val);
tans2: ratio_val;

/* (c) Validity MCQ — always "No" */
ta3: random_permutation([
  [1, false, "Yes — valid"],
  [2, true, "No — invalid (too long for this frequency)"]
]);

/* (d) Maximum valid length: l_max = 0.1 * lambda, in cm */
l_max_cm: float(0.1 * lambda_val * 100);
tans4: l_max_cm;

/* (e) R_rad at l_max: always 80*pi^2*(0.1)^2 = 0.8*pi^2 ≈ 7.896 Ohm */
R_rad_at_lmax: float(80 * %pi^2 * 0.1^2);
tans5: R_rad_at_lmax;

/* (f) P_rad using l_max */
P_rad_at_lmax: float(1/2 * I_0^2 * R_rad_at_lmax);
tans6: P_rad_at_lmax;

/* (g) Directivity in dBi — always 1.76 */
D_dBi: float(10 * log(3/2) / log(10));
tans7: D_dBi;

/* Error models */
D_linear: 1.5;
P_rad_no_half: float(I_0^2 * R_rad_at_lmax);

/* (h) R_rad scaling MCQ — halving length quarters R_rad */
ta8: random_permutation([
  [1, true, "Drops to one quarter — radiation resistance is proportional to length squared"],
  [2, false, "Drops to one half — radiation resistance is proportional to length"],
  [3, false, "Stays the same — radiation resistance depends only on frequency"],
  [4, false, "Doubles — shorter antennas radiate more efficiently"]
]);
correct_h: 1;

/* (i) Radiation efficiency with loss resistance */
R_loss: 5;
eta_rad: float(R_rad_at_lmax / (R_rad_at_lmax + R_loss));
tans9: eta_rad;

feedbackvariables.text:
/* Follow-through: compute R_rad from student's proposed l_max */
s_ratio: ans4 / (100 * lambda_val);
s_Rrad: float(80 * %pi^2 * s_ratio^2);
ft_ok: if is(abs(s_Rrad) > 0.001) and is(abs(ans5 - s_Rrad)/abs(s_Rrad) < 0.06) then 1 else 0;

s_Prad: float(1/2 * I_0^2 * s_Rrad);
ft_P_ok: if is(abs(s_Prad) > 0.0001) and is(abs(ans6 - s_Prad)/abs(s_Prad) < 0.06) then 1 else 0;
no_half: if is(abs(P_rad_no_half) > 0.001) and is(abs(ans6 - P_rad_no_half)/abs(P_rad_no_half) < 0.06) then 1 else 0;
